#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance for demonstration
    hexi::block_allocator<int, element_count> allocator;

    // Demonstrate initial state: free list is pre-populated with element_count blocks
    // (This happens in the constructor via initialise_free_list())

    // Allocate all pre-allocated blocks (uses pop() internally)
    int* blocks[element_count];
    for (size_t i = 0; i < element_count; ++i) {
        blocks[i] = allocator.allocate();
        // Each allocation calls pop(), moving head pointer forward
    }

    // At this point, free list is empty (head_ points to itself)

    // Deallocate one block (uses push() internally)
    allocator.deallocate(blocks[0]);
    // This calls push(free_block), adding the block to the head of the free list

    // Allocate another block (uses pop() again)
    int* new_block = allocator.allocate();
    // This calls pop(), which will find the previously deallocated block
    // and remove it from the head of the free list

    // Deallocate the newly allocated block
    allocator.deallocate(new_block);
    // This calls push(), adding the block back to the free list

    // Continue demonstrating with more allocations/deallocations
    // to show the circular linked list behavior
}
```

