#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Create destination buffer
    std::vector<uint8_t> destination(bytes_to_preview);

    // Use the copy function to preview data without advancing read pointer
    storage.copy(destination.data(), bytes_to_preview);

    return destination;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    // Calculate readable size using size() function
    size_t readable_size = storage.size();

    // Calculate free space using block_size and write_offset
    // Since we don't have direct access to write_offset, we can calculate it indirectly
    // Free space = total capacity - current write position
    // We know that write_offset = block_size - free_space
    // So free_space = block_size - write_offset
    // But we need to get write_offset first

    // Since we don't have a direct getter for write_offset, we can use the relationship:
    // free_space = block_size - (block_size - readable_size - read_offset)
    // However, we don't have read_offset either

    // Alternative approach: use the fact that size() = write_offset - read_offset
    // And free() function exists in the reference materials but wasn't listed in the public interface
    // Based on the advance_write function, we know there is a free() function

    // Since the reference materials show advance_write uses free(), we can assume free() is available
    size_t free_space = storage.free();

    return BufferStatus{readable_size, free_space};
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use the clear function to reset both read and write offsets to 0
    storage.clear();
}
