```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if file buffer is valid
    if (!buffer) {
        return {};
    }

    // Read the specified number of bytes into a vector
    std::vector<uint8_t> data(bytes_to_read);
    buffer.read(data.data(), bytes_to_read);

    // Check for errors during read operation
    if (buffer.error()) {
        return {};
    }

    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if file buffer is valid
    if (!buffer) {
        return {};
    }

    // Copy data without advancing read pointer
    std::vector<uint8_t> data(bytes_to_preview);
    buffer.copy(data.data(), bytes_to_preview);

    // Check for errors during copy operation
    if (buffer.error()) {
        return {};
    }

    return data;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if file buffer is valid
    if (!buffer) {
        return;
    }

    // Write the data from the vector
    buffer.write(data.data(), data.size());
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if file buffer is valid
    if (!buffer) {
        return 0;
    }

    // Return the size of the file buffer
    return buffer.size();
}
