#include <cstddef>

class CustomBuffer : public hexi::pmc::buffer_base {
    std::vector<std::byte> data_;

public:
    // Constructor to initialize the buffer
    CustomBuffer() : size_(0) {}

    // Implement the size() method to return the current size of the buffer
    std::size_t size() const override {
        return size_;
    }

    // Implement the empty() method to return whether the buffer is empty (size is 0)
    bool empty() const override {
        return size_ == 0;
    }

